import React from 'react';
import { AppProvider, useApp } from './context/AppContext';
import { AccessibilityProvider } from './context/AccessibilityContext';
import Header from './components/Header/Header';
import LeftPanel from './components/LeftPanel/LeftPanel';
import ChatInterface from './components/ChatInterface/ChatInterface';
import RightPanel from './components/RightPanel/RightPanel';
import NavigationModal from './components/Navigation/NavigationModal';
import OnboardingModal from './components/Onboarding/OnboardingModal';
import BudgetFoodFinder from './components/FoodFinder/BudgetFoodFinder';
import SecurityInfo from './components/SecurityInfo/SecurityInfo';
import FlightChangeAlert from './components/Notifications/FlightChangeAlert';
import './index.css';

function AppContent() {
  const {
    showNavigation, toggleNavigation, mobilePanel, toggleMobilePanel,
    onboardingComplete, completeOnboarding, userProfile,
    showFoodFinder, setShowFoodFinder,
    showSecurityInfo, setShowSecurityInfo,
  } = useApp();

  return (
    <div className="app-layout">
      {/* Onboarding gate */}
      {!onboardingComplete && (
        <OnboardingModal onComplete={completeOnboarding} />
      )}

      {userProfile && <FlightChangeAlert userId={userProfile.id || "local"} />}

      <a href="#chat-input" className="sr-only">Skip to chat</a>
      <Header />
      <div className="main-content">
        <LeftPanel />
        <ChatInterface />
        <RightPanel />
      </div>

      {/* Mobile bottom tabs */}
      <nav className="mobile-tabs" aria-label="Mobile navigation">
        <button className={`mobile-tab ${mobilePanel === 'left' ? 'active' : ''}`} onClick={() => toggleMobilePanel('left')}>
          <span className="mobile-tab-icon">📊</span>
          Status
        </button>
        <button className="mobile-tab active" onClick={() => toggleMobilePanel(null)}>
          <span className="mobile-tab-icon">💬</span>
          Chat
        </button>
        <button className={`mobile-tab ${mobilePanel === 'right' ? 'active' : ''}`} onClick={() => toggleMobilePanel('right')}>
          <span className="mobile-tab-icon">📍</span>
          Nearby
        </button>
      </nav>

      {showNavigation && <NavigationModal onClose={toggleNavigation} />}
      {showFoodFinder && <BudgetFoodFinder onClose={() => setShowFoodFinder(false)} />}
      {showSecurityInfo && <SecurityInfo onClose={() => setShowSecurityInfo(false)} />}
    </div>
  );
}

export default function App() {
  return (
    <AccessibilityProvider>
      <AppProvider>
        <AppContent />
      </AppProvider>
    </AccessibilityProvider>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { useChat } from '../../hooks/useChat';
import { useApp } from '../../context/AppContext';
import { suggestedPrompts } from '../../utils/mockData';
import { useVoice } from '../../hooks/useVoice';
import RouteDisplay from '../Navigation/RouteDisplay';

function parseContent(text) {
  // Simple markdown-like parsing for bold
  return text.split('\n').map((line, i) => {
    const parts = line.split(/(\*\*[^*]+\*\*)/g).map((p, j) => {
      if (p.startsWith('**') && p.endsWith('**')) {
        return <strong key={j}>{p.slice(2, -2)}</strong>;
      }
      return p;
    });
    return <span key={i}>{parts}{i < text.split('\n').length - 1 && <br />}</span>;
  });
}

function MessageBubble({ msg, feedbackGiven, onFeedback, isFirstTime, startReading }) {
  const [showNav, setShowNav] = useState(false);

  if (msg.type === 'system') {
    return (
      <div className="message system" role="alert">
        <div className="msg-bubble">{msg.content}</div>
      </div>
    );
  }

  const isUser = msg.type === 'user';

  return (
    <div className={`message ${msg.type}`}>
      {!isUser && <div className="msg-avatar">AC</div>}
      <div className="msg-bubble">
        <div className="msg-content">{parseContent(msg.content)}</div>
        {msg.steps && (
          <div className="msg-steps">
            {msg.steps.map((step, i) => (
              <div className="msg-step" key={i}>
                <div className="step-num">{i + 1}</div>
                <div className="step-text">{parseContent(step)}</div>
              </div>
            ))}
          </div>
        )}
        {msg.hasNavigation && (
          <div style={{ marginTop: '12px' }}>
            {!showNav ? (
              <button 
                className="msg-nav-btn" 
                style={{ width: '100%', background: 'var(--primary)', color: '#fff' }} 
                aria-label="Start navigation" 
                onClick={() => setShowNav(true)}
              >
                🗺️ Show Directions to {msg.navigationTo || 'Destination'}
              </button>
            ) : (
              <div style={{ marginTop: '8px', textAlign: 'left' }}>
                <button 
                  style={{ fontSize: '0.75rem', color: 'var(--text-sec)', marginBottom: '8px', cursor: 'pointer' }} 
                  onClick={() => setShowNav(false)}
                >
                  Close Navigation
                </button>
                <RouteDisplay from="Terminal 3, Main Entrance" to={msg.navigationTo || 'Gate 5B'} />
              </div>
            )}
          </div>
        )}
        {msg.hasPlaces && msg.places && (
          <div className="msg-places">
            {msg.places.map((p, i) => (
              <div className="msg-place" key={i}>
                <div style={{ flex: 1 }}>
                  <div className="msg-place-name">{p.name}</div>
                  <div className="msg-place-meta">{p.category} · {p.distance} · ⭐ {p.rating}</div>
                </div>
                <button className="nearby-nav-btn">Navigate</button>
              </div>
            ))}
          </div>
        )}
        {!isUser && (
          <div className="msg-feedback">
            <span>Helpful?</span>
            <button
              className={`feedback-btn ${feedbackGiven === 'positive' ? 'positive' : ''}`}
              onClick={() => onFeedback(msg.id, true)}
              aria-label="Helpful"
              disabled={!!feedbackGiven}
            >👍</button>
            <button
              className={`feedback-btn ${feedbackGiven === 'negative' ? 'negative' : ''}`}
              onClick={() => onFeedback(msg.id, false)}
              aria-label="Not helpful"
              disabled={!!feedbackGiven}
            >👎</button>
            {feedbackGiven && <span style={{ fontSize: '.75rem', color: '#52C41A' }}>Thanks!</span>}
            <button className="read-aloud-btn ml-2 bg-gray-800 px-2 py-1 rounded text-xs hover:bg-gray-700 transition" onClick={() => startReading(msg.content)}>
              🔊 Read Aloud
            </button>
          </div>
        )}
      </div>
      <div className="msg-time">{msg.timestamp}</div>
    </div>
  );
}

export default function ChatInterface() {
  const { flight, userMode, coordinates, userProfile, language, showNavigation, setShowNavigation, navDestination } = useApp();
  const { messages, isTyping, feedbackGiven, sendMessage, giveFeedback } = useChat();
  const { isReading, stopReading, startReading } = useVoice();
  const [input, setInput] = useState('');
  const [micActive, setMicActive] = useState(false);
  const messagesEndRef = useRef(null);
  const isFirstTime = userMode === 'first-time';

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = () => {
    if (!input.trim()) return;
    if (isReading) stopReading();
    sendMessage(input, userMode, coordinates, userProfile, language);
    setInput('');
  };

  const handleKey = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handlePrompt = (text) => {
    sendMessage(text, userMode, coordinates, userProfile, language);
  };

  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  const recognitionRef = useRef(null);

  useEffect(() => {
    if (SpeechRecognition) {
      const rec = new SpeechRecognition();
      rec.continuous = false;
      rec.interimResults = false;
      rec.lang = 'en-IN'; // Changed to English to improve transcription accuracy

      rec.onresult = (event) => {
        const transcript = event.results[0][0].transcript;
        setInput(transcript);
        setMicActive(false);
      };

      rec.onerror = (event) => {
        console.error("Speech recognition error", event.error);
        setMicActive(false);
      };

      rec.onend = () => {
        setMicActive(false);
      };

      recognitionRef.current = rec;
    }
  }, []);

  const toggleMic = () => {
    if (!recognitionRef.current) {
      alert("Your browser does not support Speech Recognition.");
      return;
    }
    if (micActive) {
      recognitionRef.current.stop();
      setMicActive(false);
    } else {
      recognitionRef.current.start();
      setMicActive(true);
    }
  };

  return (
    <main className="chat-panel" role="main" aria-label="Chat interface">
      {/* Context Bar */}
      <div className="chat-context-bar">
        <div className="info">✈️ {flight.flightNumber}</div>
        <span className="separator">|</span>
        <div className="info">🚪 Gate {flight.gate}</div>
        <span className="separator">|</span>
        <div className="info">🕐 Departs {flight.departureTime}</div>
        <span className="separator">|</span>
        <div className="info" style={{ color: '#52C41A' }}>✓ {flight.status}</div>
      </div>

      {/* Messages */}
      <div className="messages-area" role="log" aria-live="polite" aria-label="Chat messages">
        {messages.map(msg => (
          <MessageBubble
            key={msg.id}
            msg={msg}
            feedbackGiven={feedbackGiven[msg.id]}
            onFeedback={giveFeedback}
            isFirstTime={isFirstTime}
            startReading={startReading}
          />
        ))}
        {isTyping && (
          <div className="typing-indicator" aria-label="Assistant is typing">
            <div className="typing-dot" />
            <div className="typing-dot" />
            <div className="typing-dot" />
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Suggested Prompts */}
      <div className="suggested-prompts" role="list" aria-label="Suggested questions">
        {suggestedPrompts.map(p => (
          <button
            key={p.id}
            className="prompt-chip"
            onClick={() => handlePrompt(p.text)}
            role="listitem"
          >
            {p.icon} {p.text}
          </button>
        ))}
      </div>

      {/* Input */}
      <div className="chat-input-area">
        {isReading && (
          <div className="flex items-center gap-3 bg-gray-800 p-2 rounded-lg mb-2 text-sm text-blue-300">
            <div className="flex gap-1">
              <span className="w-1 h-3 bg-blue-400 animate-pulse"></span>
              <span className="w-1 h-3 bg-blue-400 animate-pulse" style={{animationDelay: '150ms'}}></span>
              <span className="w-1 h-3 bg-blue-400 animate-pulse" style={{animationDelay: '300ms'}}></span>
            </div>
            AI is reading...
            <button onClick={stopReading} className="ml-auto text-red-400 hover:text-red-300">⏸️ Pause</button>
          </div>
        )}
        <div className="chat-input-wrap">
          <input
            type="text"
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={handleKey}
            placeholder={isReading ? "Type to stop reading..." : (isFirstTime ? "Ask me anything about the airport..." : "Ask away...")}
            aria-label="Type your message"
            id="chat-input"
          />
          <button
            className={`input-btn mic ${micActive ? 'active' : ''}`}
            onClick={toggleMic}
            aria-label={micActive ? 'Stop listening' : 'Start voice input'}
          >
            🎙️
          </button>
          <button
            className="input-btn send"
            onClick={handleSend}
            disabled={!input.trim()}
            aria-label="Send message"
          >
            ➤
          </button>
        </div>
      </div>
      {/* Global Navigation Overlay (Triggered from Sidebar) */}
      {showNavigation && navDestination && (
        <div className="nav-overlay" style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(15, 23, 42, 0.95)',
          zIndex: 1000,
          padding: '20px',
          display: 'flex',
          flexDirection: 'column'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
            <h3 style={{ margin: 0, color: '#fff' }}>🗺️ Navigation to {navDestination}</h3>
            <button 
              onClick={() => setShowNavigation(false)}
              style={{ background: '#ef4444', color: '#fff', border: 'none', padding: '5px 12px', borderRadius: '4px', cursor: 'pointer' }}
            >
              Close Map
            </button>
          </div>
          <div style={{ flex: 1, overflow: 'hidden', borderRadius: '12px', background: '#1e293b' }}>
            <RouteDisplay from="Terminal Area" to={navDestination} />
          </div>
        </div>
      )}
    </main>
  );
}

import React, { useState, useRef, useEffect } from 'react';

export default function Dropdown({ trigger, children, align = 'left', className = '' }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    function handleClick(e) {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  return (
    <div className={`dropdown-wrap ${className}`} ref={ref}>
      <button
        className={`dropdown-trigger ${open ? 'open' : ''}`}
        onClick={() => setOpen(!open)}
        aria-expanded={open}
        aria-haspopup="true"
      >
        {trigger}
        <span className="arrow">▼</span>
      </button>
      {open && (
        <div className={`dropdown-menu ${align === 'right' ? 'right' : ''}`} role="menu">
          {typeof children === 'function' ? children(() => setOpen(false)) : children}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useApp } from '../../context/AppContext';

const CUISINE_CATEGORIES = {
  'Indian':           { icon: '🍛', items: ['North Indian','South Indian','Punjabi','Mughlai','Gujarati','Street Food','Momos'] },
  'Asian':            { icon: '🥢', items: ['Chinese','Thai','Japanese','Korean'] },
  'Continental':      { icon: '🍝', items: ['Continental','Italian','Multi-cuisine','Premium'] },
  'Quick Bites':      { icon: '🍔', items: ['Burgers','Pizza','Sandwiches','Wraps','Fast Food','Fried Chicken'] },
  'Beverages':        { icon: '☕', items: ['Coffee','Tea','Cafe','Juice Bar','Smoothies'] },
  'Bakery & Desserts': { icon: '🍩', items: ['Bakery','Desserts','Donuts'] },
};

export default function FoodFinder({ onClose }) {
  const { coordinates, userProfile } = useApp();
  const [selectedCuisines, setSelectedCuisines] = useState([]);
  const [dietFilter, setDietFilter] = useState(userProfile?.dietary_preference || 'both');
  const [sortBy, setSortBy] = useState('rating');
  const [priceRange, setPriceRange] = useState([]);
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);
  const [expandedCategory, setExpandedCategory] = useState(null);

  const toggleCuisine = (c) => {
    setSelectedCuisines(prev => prev.includes(c) ? prev.filter(x => x !== c) : [...prev, c]);
  };

  const togglePrice = (p) => {
    setPriceRange(prev => prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]);
  };

  const search = async () => {
    setLoading(true);
    setSearched(true);
    try {
      const res = await fetch('http://localhost:8000/api/food/recommendations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          cuisine_types: selectedCuisines,
          dietary_filter: dietFilter,
          sort_by: sortBy,
          price_range: priceRange,
          latitude: coordinates?.lat || null,
          longitude: coordinates?.lng || null,
          user_id: userProfile?.user_id || null,
        })
      });
      const data = await res.json();
      setResults(data.recommendations || []);
    } catch (err) {
      console.error('Food search error:', err);
    } finally {
      setLoading(false);
    }
  };

  // Auto-search on mount
  useEffect(() => { search(); }, []);

  return (
    <div className="modal-overlay" onClick={(e) => e.target.className === 'modal-overlay' && onClose()}>
      <div className="food-modal">
        <div className="food-modal-header">
          <h2>🍽️ Find Food & Dining</h2>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        <div className="food-modal-body">
          {/* Filters */}
          <div className="food-filters">
            {/* Cuisine Category Accordion */}
            <div className="filter-section">
              <label className="filter-label">Cuisine Type</label>
              <div className="cuisine-categories">
                {Object.entries(CUISINE_CATEGORIES).map(([cat, data]) => (
                  <div key={cat} className="cuisine-cat">
                    <button className={`cuisine-cat-header ${expandedCategory === cat ? 'expanded' : ''}`}
                      onClick={() => setExpandedCategory(expandedCategory === cat ? null : cat)}>
                      <span>{data.icon} {cat}</span>
                      <span className="expand-arrow">{expandedCategory === cat ? '▲' : '▼'}</span>
                    </button>
                    {expandedCategory === cat && (
                      <div className="cuisine-items">
                        {data.items.map(item => (
                          <button key={item}
                            className={`cuisine-chip ${selectedCuisines.includes(item) ? 'active' : ''}`}
                            onClick={() => toggleCuisine(item)}>
                            {item}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                ))}
              </div>
              {selectedCuisines.length > 0 && (
                <div className="selected-cuisines">
                  {selectedCuisines.map(c => (
                    <span key={c} className="selected-tag">{c} <button onClick={() => toggleCuisine(c)}>×</button></span>
                  ))}
                </div>
              )}
            </div>

            <div className="filter-row">
              <div className="filter-section compact">
                <label className="filter-label">Dietary</label>
                <div className="chip-group small">
                  {[{v:'both',l:'All'},{v:'veg',l:'🥬 Veg'},{v:'non_veg',l:'🍗 Non-Veg'},{v:'vegan',l:'🌱 Vegan'},{v:'jain',l:'🙏 Jain'}].map(d => (
                    <button key={d.v} className={`chip small ${dietFilter === d.v ? 'active' : ''}`}
                      onClick={() => setDietFilter(d.v)}>{d.l}</button>
                  ))}
                </div>
              </div>

              <div className="filter-section compact">
                <label className="filter-label">Sort by</label>
                <div className="chip-group small">
                  {[{v:'rating',l:'⭐ Rating'},{v:'price',l:'💰 Price'},{v:'wait_time',l:'⏱️ Wait'},{v:'distance',l:'📍 Distance'}].map(s => (
                    <button key={s.v} className={`chip small ${sortBy === s.v ? 'active' : ''}`}
                      onClick={() => setSortBy(s.v)}>{s.l}</button>
                  ))}
                </div>
              </div>
            </div>

            <button className="btn-primary search-btn" onClick={search}>
              {loading ? '⏳ Searching...' : '🔍 Search Restaurants'}
            </button>
          </div>

          {/* Results */}
          <div className="food-results">
            {loading && <div className="food-loading"><div className="typing-dot"></div><div className="typing-dot"></div><div className="typing-dot"></div></div>}
            {!loading && searched && results.length === 0 && (
              <div className="food-empty">No restaurants match your filters. Try adjusting your criteria.</div>
            )}
            {!loading && results.map(r => (
              <div key={r.id} className="restaurant-card">
                <div className="rest-header">
                  <div className="rest-name">{r.name}</div>
                  <div className="rest-rating">⭐ {r.rating}</div>
                </div>
                <div className="rest-meta">
                  <span>{r.cuisine_types?.join(' • ')}</span>
                  <span className="rest-price">{r.price_range}</span>
                </div>
                <div className="rest-details">
                  <span>📍 {r.terminal}, {r.zone?.replace(/_/g, ' ')}</span>
                  {r.walk_time_min && <span>🚶 {r.walk_time_min} min walk</span>}
                  <span>⏱️ Wait: {r.estimated_wait_time}</span>
                </div>
                <div className="rest-diet-tags">
                  {r.dietary_options?.vegetarian && <span className="diet-tag veg">✓ Veg</span>}
                  {r.dietary_options?.non_vegetarian && <span className="diet-tag nonveg">✓ Non-Veg</span>}
                  {r.dietary_options?.vegan && <span className="diet-tag vegan">✓ Vegan</span>}
                  {r.dietary_options?.jain && <span className="diet-tag jain">✓ Jain</span>}
                </div>
                <div className="rest-menu">
                  <span className="menu-label">Popular:</span>
                  {r.menu_highlights?.slice(0, 3).map(m => (
                    <span key={m.name} className="menu-item">{m.name} <small>₹{m.price}</small></span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import Dropdown from '../Common/Dropdown';
import { useApp } from '../../context/AppContext';
import { useAccessibility } from '../../context/AccessibilityContext';
import { AIRPORTS, LANGUAGES } from '../../utils/constants';

export default function Header() {
  const { airport, updateAirport, language, updateLanguage, userMode, updateUserMode } = useApp();
  const { fontSize, highContrast, updateFontSize, toggleHighContrast } = useAccessibility();
  const [search, setSearch] = useState('');

  const filtered = AIRPORTS.filter(a =>
    a.name.toLowerCase().includes(search.toLowerCase()) ||
    a.code.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <header className="header" role="banner">
      <div className="header-logo">
        <svg viewBox="0 0 28 28" fill="none" xmlns="http://www.w3.org/2000/svg">
          <circle cx="14" cy="14" r="13" fill="#E3F2FD" stroke="#60A5FA" strokeWidth="1.5"/>
          <path d="M8 17L14 7L20 17" stroke="#60A5FA" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          <path d="M10 15H18" stroke="#60A5FA" strokeWidth="1.5" strokeLinecap="round"/>
        </svg>
        <span className="logo-text">Airport Companion</span>
      </div>

      <div className="header-center">
        <Dropdown
          trigger={<><span>📍</span> {airport.name} ({airport.code})</>}
        >
          {(close) => (
            <>
              <div className="dropdown-search">
                <input
                  type="text"
                  placeholder="Search airports..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  aria-label="Search airports"
                />
              </div>
              {filtered.map(a => (
                <div
                  key={a.code}
                  className={`dropdown-item ${a.code === airport.code ? 'active' : ''}`}
                  role="menuitem"
                  onClick={() => { updateAirport(a); close(); setSearch(''); }}
                >
                  <span>✈️</span>
                  <div>
                    <div style={{ fontWeight: 600 }}>{a.city} ({a.code})</div>
                    <div style={{ fontSize: '.78rem', color: '#6C757D' }}>{a.name}</div>
                  </div>
                </div>
              ))}
            </>
          )}
        </Dropdown>
      </div>

      <div className="header-right">
        <Dropdown trigger={<>{language.flag} {language.code}</>} align="right">
          {(close) => (
            LANGUAGES.map(l => (
              <div
                key={l.code}
                className={`dropdown-item ${l.code === language.code ? 'active' : ''}`}
                role="menuitem"
                onClick={() => { updateLanguage(l); close(); }}
              >
                {l.flag} {l.name}
              </div>
            ))
          )}
        </Dropdown>

        <div className="mode-toggle" role="tablist" aria-label="User mode">
          <button
            className={userMode === 'first-time' ? 'active' : ''}
            onClick={() => updateUserMode('first-time')}
            role="tab"
            aria-selected={userMode === 'first-time'}
          >
            🌱 First Time
          </button>
          <button
            className={userMode === 'frequent' ? 'active' : ''}
            onClick={() => updateUserMode('frequent')}
            role="tab"
            aria-selected={userMode === 'frequent'}
          >
            ⭐ Frequent
          </button>
        </div>

        <Dropdown trigger={<span style={{ fontSize: '1.2rem' }}>♿</span>} align="right">
          {() => (
            <div className="a11y-menu" onClick={e => e.stopPropagation()}>
              <label>
                Font Size ({fontSize}px)
              </label>
              <input
                type="range"
                className="a11y-slider"
                min="16"
                max="20"
                step="1"
                value={fontSize}
                onChange={e => updateFontSize(Number(e.target.value))}
                aria-label="Font size"
              />
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '.75rem', color: '#6C757D', marginBottom: 16 }}>
                <span>Small</span><span>Medium</span><span>Large</span>
              </div>
              <label>
                High Contrast
                <div
                  className={`a11y-toggle ${highContrast ? 'on' : ''}`}
                  onClick={toggleHighContrast}
                  role="switch"
                  aria-checked={highContrast}
                  tabIndex={0}
                />
              </label>
            </div>
          )}
        </Dropdown>
      </div>
    </header>
  );
}

